import React, { useState, useEffect } from 'react';
import { useData } from '../../context/DataContext';
import { useAuth } from '../../context/AuthContext';

// --- CẤU HÌNH ROLE ---
const OP_ROLES = [
  { code: 'ST', label: 'Senior Teacher' },
  { code: 'TT', label: 'Tenured Teacher' },
  { code: 'CCS', label: 'Customer Care Specialist' },
  { code: 'CCO', label: 'Customer Care Officer' },
  { code: 'CCA', label: 'Customer Care Assistant' }
];

const REG_ROLES = [
  { code: 'FFM', label: 'Fresh Fit Moderator' },
  { code: 'FFS', label: 'Fresh Fit Staff' },
  { code: 'FFA', label: 'Fresh Fit Admin' }
];

const UBI_OPTIONS = [25, 50, 75, 100];

const StaffManager = () => {
  const { user } = useAuth();
  const { staffList, addStaff, deleteStaff, updatePassword, updateStaffInfo } = useData();
  
  // State thêm mới
  const [formData, setFormData] = useState({ name: '', username: '', password: '' });
  
  // State quản lý card đang mở rộng
  const [expandedId, setExpandedId] = useState(null);

  const isChief = user?.role === 'chief';
  const isOp = user?.role === 'op';
  const isReg = user?.role === 'reg';

  // --- XỬ LÝ THÊM MỚI (GIỮ NGUYÊN) ---
  const handleAdd = (e) => {
    e.preventDefault();
    if (!isChief) return alert("Không có quyền thực hiện!");
    if (!formData.name || !formData.username || !formData.password) return;
    
    addStaff({ 
      ...formData, 
      role: 'staff',
      jobTitles: [],
      ubiBase: 0,
      ubiPercent: 0,
      remuneration: 0,
      remunerationStatus: 'None'
    });
    setFormData({ name: '', username: '', password: '' });
    alert("Đã tạo tài khoản thành công");
  };

  const handleDelete = (id) => {
    if (!isChief) return;
    deleteStaff(id);
  };

  const handleResetPassword = (id) => {
    if (!isChief) return;
    const newPass = prompt("Nhập mật khẩu mới:", "123456");
    if (newPass) updatePassword(id, newPass);
  };

  // --- COMPONENT CON: STAFF CARD (XỬ LÝ LOGIC BATCH SAVE) ---
  const StaffCard = ({ staff }) => {
    const isExpanded = expandedId === staff.id;
    
    // State lưu trữ dữ liệu nháp (Draft)
    const [draft, setDraft] = useState({});
    const [isDirty, setIsDirty] = useState(false); // Đánh dấu đã có thay đổi chưa

    // Mỗi khi mở card hoặc dữ liệu gốc thay đổi, reset draft về dữ liệu gốc
    useEffect(() => {
        if (isExpanded) {
            setDraft({ ...staff });
            setIsDirty(false);
        }
    }, [isExpanded, staff]);

    // Hàm xử lý thay đổi Input thường
    const handleDraftChange = (field, value) => {
        setDraft(prev => ({ ...prev, [field]: value }));
        setIsDirty(true);
    };

    // Hàm xử lý Job Title (Checkbox)
    const toggleJobTitle = (roleCode, roleGroup) => {
        if (roleGroup === 'OP' && !isOp && !isChief) return alert("Cần quyền OP hoặc Chief!");
        if (roleGroup === 'REG' && !isReg && !isChief) return alert("Cần quyền REG hoặc Chief!");

        const currentTitles = draft.jobTitles || [];
        let newTitles;
        if (currentTitles.includes(roleCode)) {
            newTitles = currentTitles.filter(t => t !== roleCode);
        } else {
            newTitles = [...currentTitles, roleCode];
        }
        handleDraftChange('jobTitles', newTitles);
    };

    // Hàm lưu toàn bộ (Batch Save)
    const saveAllChanges = () => {
        // Chuẩn bị dữ liệu update
        const updates = {
            name: draft.name,
            phone: draft.phone,
            email: draft.email,
            role: draft.role,
            jobTitles: draft.jobTitles,
            ubiBase: draft.ubiBase,
            ubiPercent: draft.ubiPercent,
            remuneration: draft.remuneration,
            remunerationStatus: draft.remunerationStatus
        };
        updateStaffInfo(staff.id, updates);
        setIsDirty(false);
        alert("Đã cập nhật dữ liệu thành công!");
    };

    // Hàm duyệt thù lao (Hành động tức thời, không cần save batch)
    const approveRemuneration = () => {
        handleDraftChange('remunerationStatus', 'Approved');
    };

    // Tính toán UBI hiển thị (từ bản nháp)
    const ubiAmount = draft.ubiBase && draft.ubiPercent 
      ? (Number(draft.ubiBase) * (Number(draft.ubiPercent) / 100)).toLocaleString('vi-VN') 
      : 0;

    return (
      <div style={{ 
        background: '#fff', marginBottom: '15px', borderRadius: '8px', 
        boxShadow: '0 2px 8px rgba(0,0,0,0.08)',
        border: staff.role === 'chief' ? '2px solid #003366' : '1px solid #eee',
        overflow: 'hidden'
      }}>
        {/* Header Card */}
        <div 
          onClick={() => setExpandedId(isExpanded ? null : staff.id)}
          style={{ padding: '15px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', cursor: 'pointer', background: isExpanded ? '#f8f9fa' : '#fff' }}
        >
          <div style={{display: 'flex', alignItems: 'center', gap: '10px'}}>
             <div style={{
               width: '40px', height: '40px', borderRadius: '50%', 
               background: staff.role === 'chief' ? '#003366' : '#e9ecef',
               color: staff.role === 'chief' ? '#fff' : '#333',
               display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 'bold'
             }}>
               {staff.name.charAt(0).toUpperCase()}
             </div>
             <div>
               <h4 style={{margin: 0, color: '#333'}}>{staff.name} {isDirty && <span style={{color: 'red', fontSize: '0.8rem'}}>(Chưa lưu *)</span>}</h4>
               <small style={{color: '#666'}}>@{staff.username} | {staff.role?.toUpperCase()}</small>
             </div>
          </div>
          <div style={{fontSize: '0.8rem', textAlign: 'right', color: '#888'}}>
            {isExpanded ? 'Thu gọn ▲' : 'Chi tiết ▼'}
          </div>
        </div>

        {/* Body Card (Chỉnh sửa) */}
        {isExpanded && (
          <div style={{ padding: '20px', borderTop: '1px solid #eee' }}>
            
            {/* 1. SECTION: SYSTEM ROLE (CHIEF ONLY) */}
            {isChief && (
              <div style={sectionStyle}>
                <h5 style={headerStyle}>👑 System Authority (Draft)</h5>
                <label>
                    Vai trò hệ thống:
                    <select 
                      value={draft.role || 'staff'} 
                      onChange={(e) => handleDraftChange('role', e.target.value)}
                      style={inputStyle}
                    >
                      <option value="staff">Staff</option>
                      <option value="op">Operational Admin</option>
                      <option value="reg">Regulatory Admin</option>
                      <option value="chief">Chief Administrator</option>
                    </select>
                  </label>
              </div>
            )}

            {/* 2. SECTION: UBI (CHIEF ONLY) */}
            {isChief && (
              <div style={sectionStyle}>
                <h5 style={headerStyle}>💰 UBI & Lương (Draft)</h5>
                <div style={gridStyle}>
                  <label>
                    UBI Cơ bản (VNĐ):
                    <input 
                      type="number" 
                      value={draft.ubiBase || ''} 
                      onChange={(e) => handleDraftChange('ubiBase', e.target.value)}
                      style={inputStyle}
                    />
                  </label>
                  <label>
                    Phần trăm (%):
                    <select 
                      value={draft.ubiPercent || 0} 
                      onChange={(e) => handleDraftChange('ubiPercent', e.target.value)}
                      style={inputStyle}
                    >
                      <option value="0">0%</option>
                      {UBI_OPTIONS.map(opt => <option key={opt} value={opt}>{opt}%</option>)}
                    </select>
                  </label>
                </div>
                <div style={{marginTop: '5px', fontWeight: 'bold', color: '#28a745'}}>
                  Thực lãnh dự kiến: {ubiAmount} VNĐ
                </div>
              </div>
            )}

            {/* 3. SECTION: REMUNERATION (OP/CHIEF) */}
            {(isOp || isChief) && (
              <div style={sectionStyle}>
                <h5 style={headerStyle}>💸 Thù lao (Draft)</h5>
                <div style={{display: 'flex', gap: '10px', alignItems: 'flex-end'}}>
                  <label style={{flex: 1}}>
                    Đề xuất (VNĐ):
                    <input 
                      type="number"
                      value={draft.remuneration || ''}
                      onChange={(e) => {
                          handleDraftChange('remuneration', e.target.value);
                          if(draft.remunerationStatus === 'Approved') handleDraftChange('remunerationStatus', 'Pending'); // Reset status nếu sửa số
                      }}
                      style={inputStyle}
                      disabled={!isOp && !isChief} 
                    />
                  </label>
                  {isChief && (
                    <button 
                      type="button"
                      onClick={approveRemuneration}
                      disabled={draft.remunerationStatus === 'Approved'}
                      style={draft.remunerationStatus === 'Approved' ? btnDisabled : btnGreen}
                    >
                      {draft.remunerationStatus === 'Approved' ? 'Đã duyệt' : 'Duyệt'}
                    </button>
                  )}
                </div>
                <div style={{marginTop: '5px', fontSize: '0.85rem', fontStyle: 'italic', color: '#666'}}>
                    Trạng thái: {draft.remunerationStatus === 'Approved' ? 'Đã chấp thuận' : 'Chờ duyệt/Chưa có'}
                </div>
              </div>
            )}

            {/* 4. & 5. SECTION: JOB ROLES */}
            <div style={sectionStyle}>
                <h5 style={headerStyle}>🏷️ Assign Job Titles (Draft)</h5>
                
                {/* OP ROLES */}
                {(isOp || isChief) && (
                    <div style={{marginBottom: '10px'}}>
                        <strong style={{color: '#007bff', fontSize: '0.85rem'}}>Operational Roles:</strong>
                        <div style={{display: 'flex', flexWrap: 'wrap', gap: '8px', marginTop: '5px'}}>
                            {OP_ROLES.map(role => (
                                <label key={role.code} style={checkboxLabelStyle}>
                                <input 
                                    type="checkbox" 
                                    checked={(draft.jobTitles || []).includes(role.code)}
                                    onChange={() => toggleJobTitle(role.code, 'OP')}
                                />
                                {role.code}
                                </label>
                            ))}
                        </div>
                    </div>
                )}

                {/* REG ROLES */}
                {(isReg || isChief) && (
                    <div>
                        <strong style={{color: '#dc3545', fontSize: '0.85rem'}}>Regulatory Roles:</strong>
                        <div style={{display: 'flex', flexWrap: 'wrap', gap: '8px', marginTop: '5px'}}>
                            {REG_ROLES.map(role => (
                                <label key={role.code} style={checkboxLabelStyle}>
                                <input 
                                    type="checkbox" 
                                    checked={(draft.jobTitles || []).includes(role.code)}
                                    onChange={() => toggleJobTitle(role.code, 'REG')}
                                />
                                {role.code}
                                </label>
                            ))}
                        </div>
                    </div>
                )}
            </div>

            {/* ACTION BAR: NÚT CẬP NHẬT MỚI & CÁC NÚT KHÁC */}
            <div style={{ marginTop: '20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderTop: '2px solid #eee', paddingTop: '15px' }}>
                <div style={{display: 'flex', gap: '5px'}}>
                    {isChief && (
                        <>
                            <button onClick={() => handleResetPassword(staff.id)} style={btnYellow}>Đổi Pass</button>
                            <button onClick={() => handleDelete(staff.id)} style={btnRed}>Xóa</button>
                        </>
                    )}
                </div>

                <button 
                    onClick={saveAllChanges} 
                    disabled={!isDirty}
                    style={{
                        background: isDirty ? '#003366' : '#ccc',
                        color: 'white', border: 'none',
                        padding: '10px 25px', borderRadius: '4px',
                        cursor: isDirty ? 'pointer' : 'not-allowed',
                        fontWeight: 'bold', boxShadow: isDirty ? '0 2px 5px rgba(0,0,0,0.2)' : 'none'
                    }}
                >
                    💾 CẬP NHẬT THAY ĐỔI
                </button>
            </div>

          </div>
        )}
      </div>
    );
  };

  return (
    <div style={{ maxWidth: '800px', margin: '0 auto', padding: '10px' }}>
      <h2 style={{color: '#003366', textAlign: 'center'}}>Quản lý & Phân quyền</h2>
      
      {isChief && (
        <form onSubmit={handleAdd} style={{ marginBottom: '20px', padding: '15px', background: '#e3f2fd', borderRadius: '8px' }}>
          <div style={{display: 'flex', gap: '10px', flexWrap: 'wrap'}}>
            <input placeholder="Họ tên" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} required style={mainInputStyle}/>
            <input placeholder="Username" value={formData.username} onChange={e => setFormData({...formData, username: e.target.value})} required style={mainInputStyle}/>
            <input placeholder="Password" type="password" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} required style={mainInputStyle}/>
            <button type="submit" style={{...btnGreen, minWidth: '80px'}}>Thêm</button>
          </div>
        </form>
      )}

      <div>
        {staffList.map(staff => <StaffCard key={staff.id} staff={staff} />)}
      </div>
    </div>
  );
};

// --- STYLES ---
const sectionStyle = { marginBottom: '10px', padding: '10px', background: '#fcfcfc', borderRadius: '6px', border: '1px solid #f0f0f0' };
const headerStyle = { margin: '0 0 8px 0', fontSize: '0.9rem', textTransform: 'uppercase', borderBottom: '1px solid #eee', paddingBottom: '4px', color: '#555' };
const gridStyle = { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' };
const inputStyle = { width: '100%', padding: '8px', borderRadius: '4px', border: '1px solid #ccc', boxSizing: 'border-box' };
const mainInputStyle = { flex: '1 1 150px', padding: '10px', border: '1px solid #ccc', borderRadius: '4px' };
const checkboxLabelStyle = { display: 'flex', alignItems: 'center', gap: '5px', padding: '4px 8px', background: '#eee', borderRadius: '4px', fontSize: '0.8rem', cursor: 'pointer' };
const btnGreen = { background: '#28a745', color: 'white', border: 'none', padding: '8px 12px', borderRadius: '4px', cursor: 'pointer' };
const btnYellow = { background: '#ffc107', color: 'black', border: 'none', padding: '8px 12px', borderRadius: '4px', cursor: 'pointer' };
const btnRed = { background: '#dc3545', color: 'white', border: 'none', padding: '8px 12px', borderRadius: '4px', cursor: 'pointer' };
const btnDisabled = { background: '#eee', color: '#999', border: '1px solid #ddd', padding: '8px 12px', borderRadius: '4px', cursor: 'not-allowed' };

export default StaffManager;
